const leadId = $json.body?.leadId;
const status = $json.body?.status;

const statusMap = {
  nuevo: "new",
  contactado: "qualified",
  cotizado: "quoted",
  cerrado: "won",
};

return [
  {
    json: {
      leadId,
      uiStatus: status,
      dbStatus: statusMap[status] || "new",
    }
  }
];

const body = $json.body ?? {};

const orderId = body.orderId ?? body.id;
const rawStatus =
  body.status ??
  body.order_status ??
  body.nextStatus ??
  body.next_status;

if (!orderId || !rawStatus) {
  throw new Error("Faltan orderId/id o status en el body del webhook");
}

const isUuid = (value) =>
  /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(
    String(value || "")
  );

if (!isUuid(orderId)) {
  throw new Error(`orderId no es UUID válido: ${orderId}`);
}

const normalizedStatus = String(rawStatus).trim().toLowerCase();

const statusMap = {
  borrador: "draft",
  por_confirmar: "pending_confirmation",
  confirmado: "confirmed",
  pendiente_pago: "pending_payment",
  pagado_por_confirmar: "paid_pending_confirmation",
  preparacion: "in_kitchen",
  listo: "dispatched",
  entregado: "delivered",
  cancelado: "cancelled",

  draft: "draft",
  pending_confirmation: "pending_confirmation",
  confirmed: "confirmed",
  pending_payment: "pending_payment",
  paid_pending_confirmation: "paid_pending_confirmation",
  in_kitchen: "in_kitchen",
  dispatched: "dispatched",
  delivered: "delivered",
  cancelled: "cancelled",
};

const dbStatus = statusMap[normalizedStatus];

if (!dbStatus) {
  throw new Error(`Estado no soportado: ${rawStatus}`);
}

return [
  {
    json: {
      orderId: String(orderId),
      receivedStatus: rawStatus,
      normalizedStatus,
      dbStatus,
    },
  },
];

const signed = $input.first().json || {};
const receipt = $('Get Latest Payment Receipt').first().json || {};

const rawSignedUrl =
  signed.signedURL ??
  signed.signedUrl ??
  signed.url ??
  null;

const baseUrl = 'https://elastica-supabase.3haody.easypanel.host/storage/v1';

let finalUrl = null;

if (rawSignedUrl) {
  if (String(rawSignedUrl).startsWith('http://') || String(rawSignedUrl).startsWith('https://')) {
    finalUrl = rawSignedUrl;
  } else {
    finalUrl = `${baseUrl}${rawSignedUrl.startsWith('/') ? '' : '/'}${rawSignedUrl}`;
  }
}

return [
  {
    json: {
      ok: Boolean(finalUrl),
      url: finalUrl,
      paymentReceiptId: receipt.id ?? null,
      orderId: receipt.order_id ?? null,
      fileName: receipt.storage_file_name ?? null
    }
  }
];

return [
  {
    json: {
      ok: false,
      url: null,
      message: 'No se encontró un comprobante disponible para este pedido'
    }
  }
];

const raw = $input.first().json || {};
const body =
  raw.body && typeof raw.body === "object" && raw.body !== null
    ? raw.body
    : raw;

const orderId =
  body.orderId ??
  body.order_id ??
  raw.orderId ??
  raw.order_id ??
  null;

const paymentReceiptId =
  body.paymentReceiptId ??
  body.payment_receipt_id ??
  raw.paymentReceiptId ??
  raw.payment_receipt_id ??
  null;

if (!orderId || !paymentReceiptId) {
  return [
    {
      json: {
        ok: false,
        error: true,
        message: "orderId y paymentReceiptId son obligatorios",
        debug: {
          raw,
          body,
        },
      },
    },
  ];
}

return [
  {
    json: {
      ok: true,
      orderId,
      paymentReceiptId,
    },
  },
];

